const SUPPORTED_SOLAR_TERM_YEARS = [2020, 2021, 2022, 2023, 2024, 2025, 2026, 2027, 2028, 2029, 2030];

/**
 * 절기 계산 모듈
 *
 * 한국 24절기 정보를 제공합니다.
 */
/**
 * 24절기 기본 정보 조회
 * @returns 24절기 정보 배열
 */
function getAllSolarTerms() {
    return SOLAR_TERM_NAMES;
}
/**
 * 절기 인덱스로 기본 정보 조회
 * @param index 절기 인덱스 (0~23)
 * @returns 절기 기본 정보
 */
function getSolarTermInfoByIndex(index) {
    if (index < 0 || index >= 24) {
        throw new RangeError(`Solar term index must be 0~23, got ${index}`);
    }
    return SOLAR_TERM_NAMES[index];
}
/**
 * 절기 이름으로 기본 정보 조회
 * @param name 절기 이름 (예: '입춘', '경칩')
 * @returns 절기 기본 정보 또는 undefined
 */
function getSolarTermInfoByName(name) {
    return SOLAR_TERM_NAMES.find(t => t.name === name);
}
/**
 * 사주 월에 해당하는 절기 목록 조회
 * @param sajuMonth 사주 월 (1~12)
 * @returns 해당 월의 절기 목록
 */
function getSolarTermsBySajuMonth(sajuMonth) {
    if (sajuMonth < 1 || sajuMonth > 12) {
        throw new RangeError(`Saju month must be 1~12, got ${sajuMonth}`);
    }
    return SOLAR_TERM_NAMES.filter(term => term.sajuMonth === sajuMonth);
}
/**
 * 특정 연도의 모든 절기 조회 (시각 포함)
 * @param year 연도 (2020~2030)
 * @returns 해당 연도의 24절기 시각 정보
 */
function getSolarTermsByYear(year) {
    if (!SOLAR_TERMS_DATA[year]) {
        throw new Error(`No solar terms data for year ${year}. Supported years: ${SUPPORTED_SOLAR_TERM_YEARS.join(', ')}`);
    }
    const yearData = SOLAR_TERMS_DATA[year];
    const result = [];
    yearData.forEach((termData, i) => {
        // 절기 이름으로 기본 정보 찾기
        const baseInfo = SOLAR_TERM_NAMES.find(t => t.name === termData.name);
        if (!baseInfo)
            return;
        result.push({
            name: baseInfo.name,
            nameHanja: baseInfo.hanja,
            index: SOLAR_TERM_NAMES.indexOf(baseInfo),
            longitude: baseInfo.longitude,
            type: baseInfo.type,
            sajuMonth: baseInfo.sajuMonth,
            year,
            month: termData.month,
            day: termData.day,
            hour: termData.hour,
            minute: termData.minute,
        });
    });
    return result;
}
/**
 * 특정 날짜의 절기 조회 (±1일 이내)
 * @param year 연도
 * @param month 월 (1~12)
 * @param day 일 (1~31)
 * @returns 해당 날짜의 절기 정보 또는 null
 */
function getSolarTermForDate(year, month, day) {
    if (!SOLAR_TERMS_DATA[year]) {
        return null;
    }
    const yearData = SOLAR_TERMS_DATA[year];
    for (const termData of yearData) {
        if (termData.month === month && Math.abs(termData.day - day) <= 1) {
            const baseInfo = SOLAR_TERM_NAMES.find(t => t.name === termData.name);
            if (!baseInfo)
                continue;
            return {
                name: baseInfo.name,
                nameHanja: baseInfo.hanja,
                index: SOLAR_TERM_NAMES.indexOf(baseInfo),
                longitude: baseInfo.longitude,
                type: baseInfo.type,
                sajuMonth: baseInfo.sajuMonth,
                year,
                month: termData.month,
                day: termData.day,
                hour: termData.hour,
                minute: termData.minute,
            };
        }
    }
    return null;
}
/**
 * 특정 월의 모든 절기 조회
 * @param year 연도
 * @param month 월 (1~12)
 * @returns 해당 월의 절기 목록
 */
function getSolarTermsByMonth(year, month) {
    if (!SOLAR_TERMS_DATA[year]) {
        return [];
    }
    const yearData = SOLAR_TERMS_DATA[year];
    const result = [];
    yearData.forEach((termData) => {
        if (termData.month !== month)
            return;
        const baseInfo = SOLAR_TERM_NAMES.find(t => t.name === termData.name);
        if (!baseInfo)
            return;
        result.push({
            name: baseInfo.name,
            nameHanja: baseInfo.hanja,
            index: SOLAR_TERM_NAMES.indexOf(baseInfo),
            longitude: baseInfo.longitude,
            type: baseInfo.type,
            sajuMonth: baseInfo.sajuMonth,
            year,
            month: termData.month,
            day: termData.day,
            hour: termData.hour,
            minute: termData.minute,
        });
    });
    return result;
}
/**
 * 지원되는 절기 연도 목록 조회
 * @returns 지원되는 연도 배열
 */
function getSupportedSolarTermYears() {
    return [...SUPPORTED_SOLAR_TERM_YEARS];
}
/**
 * 현재 날짜가 속한 사주 월 계산
 *
 * @description
 * 사주에서 월주는 절기(節氣)를 기준으로 계산합니다.
 * 입춘(立春, 황경 315°)부터 2월, 경칩(驚蟄, 황경 345°)부터 3월, ...
 *
 * @param month 양력 월 (1~12)
 * @param day 양력 일 (1~31)
 * @returns 사주 월 (1~12)
 */
function getSajuMonth(month, day) {
    // 백엔드 코드와 동일한 방식으로 사주 월 계산
    const termDates = [
        { solarMonth: 1, day: 6, sajuMonth: 12 }, // 소한 → 축월
        { solarMonth: 2, day: 4, sajuMonth: 1 }, // 입춘 → 인월
        { solarMonth: 3, day: 6, sajuMonth: 2 }, // 경칩 → 묘월
        { solarMonth: 4, day: 5, sajuMonth: 3 }, // 청명 → 진월
        { solarMonth: 5, day: 6, sajuMonth: 4 }, // 입하 → 사월
        { solarMonth: 6, day: 6, sajuMonth: 5 }, // 망종 → 오월
        { solarMonth: 7, day: 7, sajuMonth: 6 }, // 소서 → 미월
        { solarMonth: 8, day: 8, sajuMonth: 7 }, // 입추 → 신월
        { solarMonth: 9, day: 8, sajuMonth: 8 }, // 백로 → 유월
        { solarMonth: 10, day: 8, sajuMonth: 9 }, // 한로 → 술월
        { solarMonth: 11, day: 8, sajuMonth: 10 }, // 입동 → 해월
        { solarMonth: 12, day: 7, sajuMonth: 11 }, // 대설 → 자월
    ];
    // 역순으로 검사하여 현재 날짜가 속한 월 찾기
    for (let i = termDates.length - 1; i >= 0; i--) {
        const term = termDates[i];
        if (month > term.solarMonth || (month === term.solarMonth && day >= term.day)) {
            return term.sajuMonth;
        }
    }
    // 1월 소한 이전은 자월(11) (대설 12/7 ~ 소한 1/6 구간)
    return 11;
}
/**
 * 입춘 이전인지 확인 (년주 결정에 사용)
 * @param month 양력 월
 * @param day 양력 일
 * @returns 입춘 이전이면 true
 */
function isBeforeLichun(month, day) {
    // 입춘은 대략 2월 4일
    if (month < 2) {
        return true;
    }
    if (month === 2 && day < 4) {
        return true;
    }
    return false;
}

/**
 * 출생 도시(IANA 시간대) → 출생 순간(UTC) 환산 유틸.
 *
 * 과거 서머타임(DST)은 런타임 내장 `Intl`(IANA tz 데이터)이 자동 반영한다.
 * 별도 DST 표/대형 데이터셋을 두지 않는다.
 */
/** 주어진 UTC 순간에 해당 IANA 시간대가 갖는 offset(ms, UTC 대비 양수=동쪽). */
function tzOffsetMs(timeZone, utcMs) {
    const parts = new Intl.DateTimeFormat('en-US', {
        timeZone,
        hour12: false,
        year: 'numeric',
        month: '2-digit',
        day: '2-digit',
        hour: '2-digit',
        minute: '2-digit',
        second: '2-digit',
    }).formatToParts(new Date(utcMs));
    const get = (type) => Number(parts.find((p) => p.type === type).value);
    const wallAsUtc = Date.UTC(get('year'), get('month') - 1, get('day'), get('hour') % 24, // 일부 런타임이 자정을 24로 표기하는 것을 흡수
    get('minute'), get('second'));
    return wallAsUtc - utcMs;
}
/**
 * 특정 IANA 시간대의 벽시계(local civil) 일시를 UTC 순간으로 환산한다.
 *
 * DST 전환 경계에서 offset이 달라질 수 있어, 추정 offset으로 한 번 보정해 수렴시킨다.
 */
function zonedDateTimeToUtc(year, month, day, hour, minute, timeZone) {
    const wallAsUtc = Date.UTC(year, month - 1, day, hour, minute);
    const guess = tzOffsetMs(timeZone, wallAsUtc);
    let utcMs = wallAsUtc - guess;
    const refined = tzOffsetMs(timeZone, utcMs);
    if (refined !== guess)
        utcMs = wallAsUtc - refined;
    return new Date(utcMs);
}

